do $$
declare
  demo_email_address constant text := 'demo@modelscope.local';
  demo_auth_user_id uuid;
  demo_profile_id uuid;
begin
  select au.id
  into demo_auth_user_id
  from auth.users au
  where lower(au.email) = lower(demo_email_address)
  order by au.created_at asc
  limit 1;

  if demo_auth_user_id is null then
    raise exception 'Create the demo Auth user with email % before running the app-data seed migration', demo_email_address;
  end if;

  insert into public.demo_users (auth_user_id, email, display_name)
  values (demo_auth_user_id, demo_email_address, 'ModelScope Demo Reviewer')
  on conflict (auth_user_id) do update
  set email = excluded.email,
      display_name = excluded.display_name
  returning id into demo_profile_id;

  insert into public.projects (id, name, model_label, owner_user_id)
  values
    ('residential-tower-a', 'Residential Tower A', 'Federated Model', demo_profile_id),
    ('civic-center-east', 'Civic Center East', 'Civic Coordination Model', demo_profile_id),
    ('transit-hub-02', 'Transit Hub Package 02', 'Station Federated Model', demo_profile_id)
  on conflict (id) do update
  set name = excluded.name,
      model_label = excluded.model_label,
      owner_user_id = excluded.owner_user_id;

  insert into public.project_memberships (project_id, user_id, role)
  values
    ('residential-tower-a', demo_profile_id, 'owner'),
    ('civic-center-east', demo_profile_id, 'owner'),
    ('transit-hub-02', demo_profile_id, 'owner')
  on conflict (project_id, user_id) do update
  set role = excluded.role;

  insert into public.ai_scan_runs (
    id,
    project_id,
    created_by_user_id,
    status,
    source,
    started_at,
    completed_at,
    finding_count
  )
  values
    ('8fac6b58-1280-4338-93a9-1bf6ffbb5942'::uuid, 'residential-tower-a', demo_profile_id, 'completed', 'seed', now(), now(), 18),
    ('f2454d11-edd4-4499-916a-be50a8f4105e'::uuid, 'civic-center-east', demo_profile_id, 'completed', 'seed', now(), now(), 15),
    ('e380848b-da30-4f4b-86fd-eee4002cd686'::uuid, 'transit-hub-02', demo_profile_id, 'completed', 'seed', now(), now(), 15)
  on conflict (id) do update
  set created_by_user_id = excluded.created_by_user_id,
      status = excluded.status,
      source = excluded.source,
      started_at = excluded.started_at,
      completed_at = excluded.completed_at,
      finding_count = excluded.finding_count;

  insert into public.ai_findings (
    id,
    project_id,
    scan_run_id,
    fixture_finding_id,
    code,
    title,
    finding_type,
    suggested_priority,
    confidence,
    object_id,
    object_label,
    discipline,
    level,
    location,
    source_payload,
    current_status
  )
